console.log("[SeenYT] Background script loaded.");chrome.runtime.onInstalled.addListener(()=>{console.log("[SeenYT] Extension installed successfully!")});chrome.runtime.onMessage.addListener((t,r,n)=>{if(t.type==="SEENYT_BG_FETCH"){const{url:o,options:s}=t;console.log("[SeenYT-BG] Fetching:",o);const l={...s,credentials:"include"};return fetch(o,l).then(async e=>{const c=await e.text();return console.log(`[SeenYT-BG] Status: ${e.status}, Length: ${c.length}`),{ok:e.ok,status:e.status,text:c}}).then(e=>{n(e)}).catch(e=>{console.error("[SeenYT-BG] Error:",e),n({ok:!1,error:String(e)})}),!0}});
